  // Find word with max length
}

solution:
function findLongestWord(str) {
  if (!str) return "";
  const words = str.split(" ");
  let longest = "";
  for (let word of words) {
    if (word.length > longest.length) {
      longest = word;
    }
  }
  return longest;
}

